import{_ as r,o as n,c as o,ae as s}from"./chunks/framework.Db9uaNqL.js";const m=JSON.parse('{"title":"Unit 2: am/is/are (Questions)","description":"","frontmatter":{},"headers":[],"relativePath":"English/《Essential Grammar in Use》/Unit2.md","filePath":"English/《Essential Grammar in Use》/Unit2.md","lastUpdated":1777664125000}'),e={name:"English/《Essential Grammar in Use》/Unit2.md"};function a(i,t,l,g,h,u){return n(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="unit-2-am-is-are-questions" tabindex="-1"><strong>Unit 2: am/is/are (Questions)</strong> <a class="header-anchor" href="#unit-2-am-is-are-questions" aria-label="Permalink to &quot;**Unit 2: am/is/are (Questions)**&quot;">​</a></h1><h4 id="语法重点-be-动词的疑问句形式" tabindex="-1"><strong>语法重点：be 动词的疑问句形式</strong> <a class="header-anchor" href="#语法重点-be-动词的疑问句形式" aria-label="Permalink to &quot;**语法重点：be 动词的疑问句形式**&quot;">​</a></h4><p>这个单元的重点是如何使用 <strong>am / is / are</strong> 来构造 <strong>疑问句</strong>。</p><h4 id="_1-一般疑问句" tabindex="-1"><strong>1. 一般疑问句</strong> <a class="header-anchor" href="#_1-一般疑问句" aria-label="Permalink to &quot;**1. 一般疑问句**&quot;">​</a></h4><p>为了构成疑问句，我们需要将 <strong>am / is / are</strong> 放到句首，紧接着是主语。</p><h5 id="规则" tabindex="-1"><strong>规则</strong> <a class="header-anchor" href="#规则" aria-label="Permalink to &quot;**规则**&quot;">​</a></h5><ul><li><strong>I + am</strong> → <strong>Am I...?</strong> 例：Am I late? (我迟到了吗？)</li><li><strong>he / she / it + is</strong> → <strong>Is he / she / it...?</strong> 例：Is she your friend? (她是你的朋友吗？)</li><li><strong>you / we / they + are</strong> → <strong>Are you / we / they...?</strong> 例：Are they your parents? (他们是你的父母吗？)</li></ul><h4 id="_2-否定疑问句" tabindex="-1"><strong>2. 否定疑问句</strong> <a class="header-anchor" href="#_2-否定疑问句" aria-label="Permalink to &quot;**2. 否定疑问句**&quot;">​</a></h4><p>通过将 <strong>not</strong> 加入 <strong>be 动词</strong> 后形成 <strong>否定疑问句</strong>，通常是为了表示怀疑或者询问是否不符合某种预期。</p><h5 id="规则-1" tabindex="-1"><strong>规则</strong> <a class="header-anchor" href="#规则-1" aria-label="Permalink to &quot;**规则**&quot;">​</a></h5><ul><li><strong>I + am not</strong> → <strong>Aren&#39;t I...?</strong> 例：Aren&#39;t I right? (我不是对的吗？)</li><li><strong>he / she / it is not (isn&#39;t)</strong> → <strong>Isn&#39;t he / she / it...?</strong> 例：Isn&#39;t it cold outside? (外面不冷吗？)</li><li><strong>you / we / they are not (aren&#39;t)</strong> → <strong>Aren&#39;t you / we / they...?</strong> 例：Aren&#39;t you coming to the party? (你不来派对吗？)</li></ul><h4 id="_3-结构总结" tabindex="-1"><strong>3. 结构总结</strong> <a class="header-anchor" href="#_3-结构总结" aria-label="Permalink to &quot;**3. 结构总结**&quot;">​</a></h4><ul><li><strong>疑问句结构</strong>： <ul><li><strong>Am I...?</strong></li><li><strong>Is he / she / it...?</strong></li><li><strong>Are you / we / they...?</strong></li></ul></li><li><strong>否定疑问句结构</strong>： <ul><li><strong>Aren&#39;t I...?</strong></li><li><strong>Isn&#39;t he / she / it...?</strong></li><li><strong>Aren&#39;t you / we / they...?</strong></li></ul></li></ul><h4 id="_4-常见用法" tabindex="-1"><strong>4. 常见用法</strong> <a class="header-anchor" href="#_4-常见用法" aria-label="Permalink to &quot;**4. 常见用法**&quot;">​</a></h4><ul><li><strong>疑问句</strong>：用于寻求确认或了解某件事情。 <ul><li>例：<strong>Is it your book?</strong> (这是你的书吗？)</li></ul></li><li><strong>否定疑问句</strong>：通常用来表示某种怀疑或预期不成立的情况。 <ul><li>例：<strong>Aren&#39;t you tired?</strong> (你不累吗？)</li></ul></li></ul><h4 id="总结" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;**总结**&quot;">​</a></h4><ul><li><strong>一般疑问句</strong>：将 <strong>am / is / are</strong> 放在主语前面。</li><li><strong>否定疑问句</strong>：在 <strong>am / is / are</strong> 后加上 <strong>not</strong>，有时可以使用缩写形式，如 <strong>aren&#39;t</strong> 和 <strong>isn&#39;t</strong>。</li></ul><h4 id="练习题" tabindex="-1"><strong>练习题</strong> <a class="header-anchor" href="#练习题" aria-label="Permalink to &quot;**练习题**&quot;">​</a></h4><ol><li><strong>一般疑问句</strong>： <strong>___ you my friend?</strong> (Are)</li><li><strong>否定疑问句</strong>： <strong>___ he your brother?</strong> (Isn&#39;t)</li></ol><p>通过这一单元，你应该能够掌握如何用 <strong>be 动词</strong> 构成疑问句，进行日常交流和提问。如果有其他问题或需要更多例子，请随时告诉我！</p>',20)])])}const c=r(e,[["render",a]]);export{m as __pageData,c as default};
